insert into public.exercises (name, description, cues, log_type, auto_load, increment_lb) values
('Barbell Hip Thrust','Shoulders on bench, barbell over hips, drive hips up to full lockout and squeeze glutes.',ARRAY['Ribs down, posterior pelvic tilt at top','Push through heels','Chin tucked, eyes forward','Full lockout, brief squeeze'],'sets_weight',true,5),
